 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import {
 4	  Button,
 5	  EmptyState,
 6	  EmptyStateVariant,
 7	  EmptyStateIcon,
 8	  EmptyStateBody,
 9	  Tooltip,
10	  EmptyStateHeader,
11	  EmptyStateFooter,
12	} from '@patternfly/react-core';
13	import { CubesIcon } from '@patternfly/react-icons';
14	import './empty-page.scss';
15	
16	const EmptyPage: React.FC<EmptyPageProps> = (props) => {
17	  const { t } = useCustomTranslation();
18	
19	  const {
20	    title,
21	    children,
22	    buttonText,
23	    canAccess,
24	    isLoaded,
25	    onClick,
26	    ButtonComponent,
27	    isDisabled,
28	    EmptyIcon = CubesIcon,
29	  } = props;
30	  return !isLoaded ? (
31	    <div
32	      className="loading-skeleton--table mco-empty-page__skeleton"
33	      aria-label={t('Loading empty page')}
34	    />
35	  ) : (
36	    <EmptyState variant={EmptyStateVariant.lg}>
37	      <EmptyStateHeader
38	        titleText={<>{title}</>}
39	        icon={<EmptyStateIcon icon={EmptyIcon} />}
40	        headingLevel="h4"
41	      />
42	      <EmptyStateBody>{children}</EmptyStateBody>
43	      <EmptyStateFooter>
44	        <Tooltip
45	          content={
46	            !canAccess &&
47	            t(
48	              'You are not authorized to complete this action. See your cluster administrator for role-based access control information.'
49	            )
50	          }
51	          trigger={!canAccess ? 'mouseenter' : 'manual'}
52	          data-test="authorization-tooltip"
53	          aria-label={t('Not Authorized')}
54	        >
55	          {!!ButtonComponent ? (
56	            <ButtonComponent />
57	          ) : (
58	            <Button
59	              variant="primary"
60	              onClick={onClick}
61	              isAriaDisabled={!canAccess}
62	              data-test="create-button"
63	              aria-label={t('Empty Page')}
64	              isDisabled={isDisabled}
65	            >
66	              {buttonText}
67	            </Button>
68	          )}
69	        </Tooltip>
70	      </EmptyStateFooter>
71	    </EmptyState>
72	  );
73	};
74	
75	type EmptyPageProps = {
76	  title: string;
77	  children?: any;
78	  buttonText?: string;
79	  canAccess?: boolean;
80	  isLoaded?: boolean;
81	  onClick?: () => void;
82	  ButtonComponent?: React.FC<unknown>;
83	  isDisabled?: boolean;
84	  EmptyIcon?: React.ComponentType<any>;
85	};
86	
87	export default EmptyPage;

